Use ASP.NET Core's **`WebApplicationFactory<T>`** from `Microsoft.AspNetCore.Mvc.Testing`. It spins up your entire middleware pipeline in-memory — no real port, no network.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test (xUnit)

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (stateful session — send Mcp-Session-Id if needed)
        var init = new { jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" } } };
        var initResp = await _client.PostAsJsonAsync("/mcp", init);
        // Extract session ID from response header if your server uses one
        var sessionId = initResp.Headers.TryGetValues("Mcp-Session-Id", out var vals)
            ? vals.First() : null;

        var listReq = new HttpRequestMessage(HttpMethod.Post, "/mcp");
        listReq.Content = JsonContent.Create(new {
            jsonrpc = "2.0", id = 2, method = "tools/list" });
        if (sessionId != null)
            listReq.Headers.Add("Mcp-Session-Id", sessionId);

        var resp = await _client.SendAsync(listReq);
        resp.EnsureSuccessStatusCode();
        var body = await resp.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real server** | `WebApplicationFactory` hosts in-process via `TestServer` |
| **Full pipeline** | Middleware, DI, routing all run as in production |
| **Session state** | Capture `Mcp-Session-Id` header and pass it on subsequent requests |
| **SSE streams** | Use `HttpCompletionOption.ResponseHeadersRead` + read the stream line-by-line |
| **External deps** | Override DI in `WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in fakes |
| **`Program` visibility** | Add `[assembly: InternalsVisibleTo("MyMcp.Tests")]` or a partial `public partial class Program { }` in your server project |

This gives you real HTTP-level integration tests with zero network overhead.
